mapper.select:
SELECT id, project_id, document_id, version_name, chunk_index, title, content, token_count, metadata, embedding::text AS embedding, embedding_model, embedding_status, embedding_error_message, chunk_type, parent_chunk_id, section_path, module_name, requirement_id, start_position, end_position, source_type, enabled, deleted, created_at, updated_at, embedding <=> #{queryEmbedding}::vector AS distance FROM knowledge_chunk WHERE project_id = #{projectId} AND enabled = true AND deleted = false AND embedding IS NOT NULL AND embedding_status = 'EMBEDDED'
AND version_name = #{versionName}
ORDER BY embedding <=> #{queryEmbedding}::vector LIMIT #{topK}
